insert into public.course_catalog (slug, name, holes, par, yardage, walkability, rate_notes, twilight_discount, rates_updated_at, booking_url_template, editorial_note, prepaid) values ('barn-golf-club-ogden', 'Barn Golf Club (Ogden)', 18, 72, 6128, 'moderate', 'Weekday Rates: Monday - Thursday\nWeekend Rates: Friday - Sunday', false, '2026-07-08', 'https://golfpay.co/course/the-barn-golf-club-ogden-ut-84414?lp=1&_gshcid=1466&_gsrefsrc=acquisition&date=2026-07-09&sort=lowest_price', 'Located just 2 miles East of I-15 at exit 349 is your #1 option for golf in Ogden Utah. The Barn Golf Club is a privately owned and family-operated golf course located in the foothills of the majestic Ben Lomond peak. Featuring 18 beautiful golf holes along with 2 practice greens, a driving range, a full-service snack bar, and a well-stocked Pro shop full of top brand name merchandise.', true) on conflict (slug) do update set holes = excluded.holes, par = excluded.par, yardage = excluded.yardage, walkability = excluded.walkability, rate_notes = excluded.rate_notes, twilight_discount = excluded.twilight_discount, rates_updated_at = excluded.rates_updated_at, booking_url_template = excluded.booking_url_template, editorial_note = excluded.editorial_note, prepaid = excluded.prepaid, updated_at = now();
insert into public.course_catalog (slug, name, holes, par, yardage, walkability, rate_notes, twilight_discount, rates_updated_at, booking_url_template, editorial_note, prepaid) values ('bear-lake-garden-city', 'Bear Lake (Garden City)', 9, 36, 3376, 'moderate', 'Weekday Rates: Monday - Thursday\nWeekend Rates: Friday - Sunday', false, '2026-07-08', 'https://foreupsoftware.com/index.php/booking/18905/609#/teetimes', 'Come out and experience Bear Lake Golf Course. Bear Lake is an exciting 9 hole regulation course located at the Bear Lake Golf Course facility in Garden City, UT. From the longest tees it presents 3,376 yards of golf for a par of 36. The course was designed by William H. Neff, ASGCA and opened in 1971.', false) on conflict (slug) do update set holes = excluded.holes, par = excluded.par, yardage = excluded.yardage, walkability = excluded.walkability, rate_notes = excluded.rate_notes, twilight_discount = excluded.twilight_discount, rates_updated_at = excluded.rates_updated_at, booking_url_template = excluded.booking_url_template, editorial_note = excluded.editorial_note, prepaid = excluded.prepaid, updated_at = now();
insert into public.course_catalog (slug, name, holes, par, yardage, walkability, rate_notes, twilight_discount, booking_url_template, editorial_note, prepaid) values ('black-desert-resort-ivins', 'Black Desert Resort (Ivins)', 18, 72, 7500, 'carts only', '2026 Rates        January 2 - March 12        March 13 – July 6        July 7 – September 3, 10:15 AM - Close        September 4 – January 1, 2027\nResort Guest:        $250        $325        $250        $325\nNon-Resort Guest:        $325        $450        $325        $450', false, 'https://www.chronogolf.com/club/black-desert-resort?', 'Vermilion cliffs. Cobalt skies. Crimson peaks. In a landscape this breathtaking, we offer something more—Tom Weiskopf’s final masterpiece. Discover why Golfweek named Black Desert Resort the #1 course in Utah. You’ll find it on many of the prestigious publication’s most coveted lists: #34 on their nationwide “Top 100 Best Courses you can play in the U.S.” ranking, and #96 on the “Top 200 Modern Courses” list.', false) on conflict (slug) do update set holes = excluded.holes, par = excluded.par, yardage = excluded.yardage, walkability = excluded.walkability, rate_notes = excluded.rate_notes, twilight_discount = excluded.twilight_discount, booking_url_template = excluded.booking_url_template, editorial_note = excluded.editorial_note, prepaid = excluded.prepaid, updated_at = now();
insert into public.course_catalog (slug, name, holes, par, yardage, walkability, rate_notes, twilight_discount, rates_updated_at, booking_window_days, booking_url_template, editorial_note, prepaid) values ('bonneville-slc', 'Bonneville (SLC)', 18, 72, 6729, 'hilly', '18-hole rate; 9 holes $25 (off 10th tee first 90 min daily). 18 holes only until 4pm Fri-Sun and holidays. Advance reservation outside 7-day window: $20/player.', false, '2026-07-08', 7, 'https://www.chronogolf.com/club/bonneville-golf-course/booking/', 'Now, almost one hundred years since the opening of the original nine-holes, Bonneville continues to be renowned for its superb conditions and classic layout. Situated on the East Bench of Salt Lake City, just 5 minutes away from the heart of downtown, this gem offers awe-inspiring sunsets and views of both the surrounding mountains and the entire Salt Lake valley.', false) on conflict (slug) do update set holes = excluded.holes, par = excluded.par, yardage = excluded.yardage, walkability = excluded.walkability, rate_notes = excluded.rate_notes, twilight_discount = excluded.twilight_discount, rates_updated_at = excluded.rates_updated_at, booking_window_days = excluded.booking_window_days, booking_url_template = excluded.booking_url_template, editorial_note = excluded.editorial_note, prepaid = excluded.prepaid, updated_at = now();
insert into public.course_catalog (slug, name, holes, par, yardage, walkability, rate_notes, twilight_discount, rates_updated_at, booking_window_days, booking_url_template, editorial_note, history_blurb, prepaid) values ('bountiful-ridge-bountiful', 'Bountiful Ridge (Bountiful)', 18, 71, 6523, 'hilly', '18-hole rates: Mon-Thu $36, Fri-Sun & holidays $46; 9 holes $18/$23. All tee times prepaid; max 2 tee times per person per day. Season roughly Mar-Nov.', false, '2026-07-08', 4, 'https://foreupsoftware.com/index.php/booking/18950#/teetimes', 'Perched on the east bench with panoramic lake and valley views. Legit elevation change — one of the tougher walks on the Wasatch Front. No driving range, so warm up before you arrive; the short 4-day window means weekend times vanish fast.', 'Opened in 1975; designed by William H. Neff.', true) on conflict (slug) do update set holes = excluded.holes, par = excluded.par, yardage = excluded.yardage, walkability = excluded.walkability, rate_notes = excluded.rate_notes, twilight_discount = excluded.twilight_discount, rates_updated_at = excluded.rates_updated_at, booking_window_days = excluded.booking_window_days, booking_url_template = excluded.booking_url_template, editorial_note = excluded.editorial_note, history_blurb = excluded.history_blurb, prepaid = excluded.prepaid, updated_at = now();
