insert into public.course_catalog (slug, name, holes, par, yardage, rate_notes, rates_updated_at, booking_url_template, editorial_note) values ('carbon-cc-helper', 'Carbon CC (Helper)', 18, 70, 6159, 'Same Rates Monday - Sunday', '2026-07-08', 'https://foreupsoftware.com/index.php/booking/22113/9906#/teetimes', 'Located midway between Helper and Price, Carbon Country Club is where you will discover the alluring beauty of the Utah frontier sculpted into a one-of-a-kind golf experience. Set within chiseled mesas and rocky valleys, play our golf course that continues to be an oasis for our members and guests year after year. Whether new to the game or a passionate veteran of golf, Carbon Country Club offers you the experience that you will forever enjoy.') on conflict (slug) do update set holes = excluded.holes, par = excluded.par, yardage = excluded.yardage, rate_notes = excluded.rate_notes, rates_updated_at = excluded.rates_updated_at, booking_url_template = excluded.booking_url_template, editorial_note = excluded.editorial_note, updated_at = now();
