insert into public.course_catalog (slug, name, holes, par, walkability, editorial_note, history_blurb) values ('el-monte-ogden', 'El Monte (Ogden)', 9, 35, 'moderate', 'A historic little 9 at the mouth of Ogden Canyon — short, shady, and cheap, with canyon walls right there. One of the oldest courses in the state and a quick, charming loop.', 'One of Utah’s oldest courses, dating to the 1920s at the mouth of Ogden Canyon.') on conflict (slug) do update set holes = excluded.holes, par = excluded.par, walkability = excluded.walkability, editorial_note = excluded.editorial_note, history_blurb = excluded.history_blurb, updated_at = now();
