insert into public.course_catalog (slug, name, holes, par, walkability, rate_notes, twilight_discount, rates_updated_at, booking_window_days, editorial_note, history_blurb, prepaid) values ('forest-dale-slc', 'Forest Dale (SLC)', 9, 36, 'moderate', '9-hole course; 18-hole cells reflect two loops. Same rate all week. Indoor simulators on site. Advance reservation outside 7-day window: $10/player. Cart per rider.', false, '2026-07-08', 7, 'Tight, tree-lined 9 in Sugar House with old-school charm and a walkable footprint. Great winter option with the simulator building.', 'Opened in the early 1900s as the original home of the Salt Lake Country Club — one of the oldest courses in Utah.', false) on conflict (slug) do update set holes = excluded.holes, par = excluded.par, walkability = excluded.walkability, rate_notes = excluded.rate_notes, twilight_discount = excluded.twilight_discount, rates_updated_at = excluded.rates_updated_at, booking_window_days = excluded.booking_window_days, editorial_note = excluded.editorial_note, history_blurb = excluded.history_blurb, prepaid = excluded.prepaid, updated_at = now();
