insert into public.course_catalog (slug, name, holes, par, walkability, rate_notes, twilight_discount, rates_updated_at, booking_window_days, editorial_note, prepaid) values ('glendale-slc', 'Glendale (SLC)', 18, 72, 'flat', 'Same public rate weekdays & weekends; passes not valid before 2pm on weekends/holidays. Advance reservation outside 7-day window: $15/player. Cart priced per rider.', false, '2026-07-08', 7, 'West-side muni along the Jordan River with wide, forgiving fairways and some of the most in-demand tee times in the valley. Flat, fast walk. Be online the minute the 7-day window opens.', false) on conflict (slug) do update set holes = excluded.holes, par = excluded.par, walkability = excluded.walkability, rate_notes = excluded.rate_notes, twilight_discount = excluded.twilight_discount, rates_updated_at = excluded.rates_updated_at, booking_window_days = excluded.booking_window_days, editorial_note = excluded.editorial_note, prepaid = excluded.prepaid, updated_at = now();
insert into public.course_catalog (slug, name, holes, par, walkability, editorial_note, signature_hole) values ('green-spring-st-george', 'Green Spring (St. George)', 18, 71, 'hilly', 'Best known for its lava-rock quarry stretch — the mid-round holes plunging through a black-rock ravine are among the most photographed in southern Utah. Semi-private feel, upper-tier conditioning.', 'The quarry holes (8-10) — forced carries across a lava-rock ravine') on conflict (slug) do update set holes = excluded.holes, par = excluded.par, walkability = excluded.walkability, editorial_note = excluded.editorial_note, signature_hole = excluded.signature_hole, updated_at = now();
