insert into public.course_catalog (slug, name, holes, par, walkability, editorial_note) values ('homestead-midway', 'Homestead (Midway)', 18, 72, 'moderate', 'Resort course in the Heber Valley next to the Homestead Crater — mature, well-conditioned, and set against the mountains. A relaxed destination round with a resort feel.') on conflict (slug) do update set holes = excluded.holes, par = excluded.par, walkability = excluded.walkability, editorial_note = excluded.editorial_note, updated_at = now();
insert into public.course_catalog (slug, name, holes, par, walkability, editorial_note) values ('lakeside-west-bountiful', 'Lakeside (West Bountiful)', 18, 71, 'flat', 'Flat, water-dotted course in West Bountiful — easy walking and forgiving off the tee. A good pick for a laid-back round or newer players.') on conflict (slug) do update set holes = excluded.holes, par = excluded.par, walkability = excluded.walkability, editorial_note = excluded.editorial_note, updated_at = now();
insert into public.course_catalog (slug, name, holes, par, walkability, editorial_note) values ('logan-river-logan', 'Logan River (Logan)', 18, 72, 'flat', 'Flat course winding along the Logan River in Cache Valley — walkable and scenic, with water frequently in play. Cooler northern-Utah climate.') on conflict (slug) do update set holes = excluded.holes, par = excluded.par, walkability = excluded.walkability, editorial_note = excluded.editorial_note, updated_at = now();
insert into public.course_catalog (slug, name, holes, par, yardage, walkability, editorial_note) values ('meadow-brook-slc', 'Meadow Brook (SLC)', 18, 72, 6694, 'flat', 'Classic old-style parkland in the center of the valley — flat, easy walk, forgiving, and cheap for a regulation 18. A solid choice when the marquee courses are booked out.') on conflict (slug) do update set holes = excluded.holes, par = excluded.par, yardage = excluded.yardage, walkability = excluded.walkability, editorial_note = excluded.editorial_note, updated_at = now();
insert into public.course_catalog (slug, name, holes, par, walkability, editorial_note) values ('mick-riley-murray', 'Mick Riley (Murray)', 9, 36, 'flat', 'The valley’s beginner headquarters — a friendly regulation 9 plus a separate par-3 course, full range, and the county’s junior golf hub. Flat, cheap, and zero intimidation factor.') on conflict (slug) do update set holes = excluded.holes, par = excluded.par, walkability = excluded.walkability, editorial_note = excluded.editorial_note, updated_at = now();
insert into public.course_catalog (slug, name, holes, walkability, rate_notes, twilight_discount, rates_updated_at, booking_window_days, editorial_note, prepaid) values ('mountain-dell-slc', 'Mountain Dell (SLC)', 18, 'hilly', 'Two 18s (Lake & Canyon), same rate. 18 holes only until 4pm Thu-Sun/holidays. Weekend/holiday 9-hole cart is $20/rider (vs $10 weekday). Advance reservation outside 7-day window: $20/player.', false, '2026-07-08', 7, 'Two 18s up Parleys Canyon — genuine mountain golf 15 minutes from downtown. Cooler temps, elevation change, and the occasional elk. Canyon is the sportier walk; Lake plays bigger.', false) on conflict (slug) do update set holes = excluded.holes, walkability = excluded.walkability, rate_notes = excluded.rate_notes, twilight_discount = excluded.twilight_discount, rates_updated_at = excluded.rates_updated_at, booking_window_days = excluded.booking_window_days, editorial_note = excluded.editorial_note, prepaid = excluded.prepaid, updated_at = now();
insert into public.course_catalog (slug, name, holes, par, yardage, walkability, editorial_note) values ('mountain-view-west-jordan', 'Mountain View (West Jordan)', 18, 72, 6764, 'flat', 'Spacious fairways, generous greens, and wall-to-wall Wasatch views from the west side. Straightforward, flat walk that suits every skill level — a dependable mid-priced 18.') on conflict (slug) do update set holes = excluded.holes, par = excluded.par, yardage = excluded.yardage, walkability = excluded.walkability, editorial_note = excluded.editorial_note, updated_at = now();
