insert into public.course_catalog (slug, name, holes, par, walkability, editorial_note) values ('murray-parkway-murray', 'Murray Parkway (Murray)', 18, 72, 'flat', 'Flat, mature parkway course along the Jordan River in Murray — central, walkable, and consistently good value. An easy after-work 18.') on conflict (slug) do update set holes = excluded.holes, par = excluded.par, walkability = excluded.walkability, editorial_note = excluded.editorial_note, updated_at = now();
insert into public.course_catalog (slug, name, holes, par, walkability, rate_notes, twilight_discount, rates_updated_at, booking_window_days, editorial_note, history_blurb, prepaid) values ('nibley-park-slc', 'Nibley Park (SLC)', 9, 34, 'flat', '9-hole course; 18-hole cells reflect two loops. Same rate all week. Advance reservation outside 7-day window: $10/player. Cart per rider.', false, '2026-07-08', 7, 'Historic city 9-holer — short, social, and beginner-friendly. The classic grab-a-quick-nine course in the middle of town.', 'Dates to the early 1920s on land donated by Charles W. Nibley — one of Salt Lake City''s oldest public courses.', false) on conflict (slug) do update set holes = excluded.holes, par = excluded.par, walkability = excluded.walkability, rate_notes = excluded.rate_notes, twilight_discount = excluded.twilight_discount, rates_updated_at = excluded.rates_updated_at, booking_window_days = excluded.booking_window_days, editorial_note = excluded.editorial_note, history_blurb = excluded.history_blurb, prepaid = excluded.prepaid, updated_at = now();
insert into public.course_catalog (slug, name, holes, par, walkability, editorial_note, history_blurb) values ('old-mill-slc', 'Old Mill (SLC)', 18, 71, 'hilly', 'The premium county track — bench-side setting off I-215 with big valley views, a legit clubhouse, and conditions a cut above the other county courses. Priced accordingly at $44.', 'Gene Bates design; one of the newer courses in the Salt Lake area.') on conflict (slug) do update set holes = excluded.holes, par = excluded.par, walkability = excluded.walkability, editorial_note = excluded.editorial_note, history_blurb = excluded.history_blurb, updated_at = now();
