insert into public.course_catalog (slug, name, holes, par, walkability, rate_notes, twilight_discount, rates_updated_at, booking_window_days, editorial_note, prepaid) values ('rose-park-slc', 'Rose Park (SLC)', 18, 72, 'flat', 'Same public rate weekdays & weekends; passes not valid before 2pm on weekends/holidays. Advance reservation outside 7-day window: $15/player. Cart priced per rider.', false, '2026-07-08', 7, 'Flat, walkable, and quick by SLC standards — a go-to for after-work nines. Wind is the main defense. One of the best value 18s in the city.', false) on conflict (slug) do update set holes = excluded.holes, par = excluded.par, walkability = excluded.walkability, rate_notes = excluded.rate_notes, twilight_discount = excluded.twilight_discount, rates_updated_at = excluded.rates_updated_at, booking_window_days = excluded.booking_window_days, editorial_note = excluded.editorial_note, prepaid = excluded.prepaid, updated_at = now();
insert into public.course_catalog (slug, name, holes, par, walkability, editorial_note, signature_hole) values ('sand-hollow-championship-hurricane', 'Sand Hollow Championship (Hurricane)', 18, 72, 'moderate', 'The most nationally recognized public course in Utah — links-inspired golf through red sandstone with the famous cliffside stretch above the reservoir. Books out early; play spring or fall, not July heat.', 'No. 15 — the clifftop par 3 over the sandstone canyon') on conflict (slug) do update set holes = excluded.holes, par = excluded.par, walkability = excluded.walkability, editorial_note = excluded.editorial_note, signature_hole = excluded.signature_hole, updated_at = now();
