insert into public.course_catalog (slug, name, holes, par, walkability, editorial_note) values ('sky-mountain-hurricane', 'Sky Mountain (Hurricane)', 18, 72, 'hilly', 'One of the best scenery-per-dollar rounds in the state — a well-priced desert-mountain course with jaw-dropping views toward Zion. Elevation changes make it a real walk.') on conflict (slug) do update set holes = excluded.holes, par = excluded.par, walkability = excluded.walkability, editorial_note = excluded.editorial_note, updated_at = now();
