insert into public.course_catalog (slug, name, holes, par, yardage, walkability, editorial_note, history_blurb) values ('south-mountain-draper', 'South Mountain (Draper)', 18, 72, 7080, 'carts only', 'Mountain-links style on the Draper foothills — dramatic elevation change, huge undulating greens, five tee sets, and a range that opens May through October. Note for walkers: carts are mandatory here, so this one never counts toward the on-foot list.', 'Opened in 1998, designed by David Graham and Gary Panks. Host of the 1999 Utah Open and once ranked as high as #3 in Utah by Golf Digest.') on conflict (slug) do update set holes = excluded.holes, par = excluded.par, yardage = excluded.yardage, walkability = excluded.walkability, editorial_note = excluded.editorial_note, history_blurb = excluded.history_blurb, updated_at = now();
